-- 20240411_MoodB_Platform_Expansion.sql\n-- 의료 플랫폼 비즈니스 모델을 위한 DB 스키마 확장\n\n-- 1. 사용자 프로필 테이블 확장\nDO  \nBEGIN\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='role') THEN\n        ALTER TABLE public.profiles ADD COLUMN role TEXT DEFAULT 'general' CHECK (role IN ('general', 'doctor', 'patient'));\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='age') THEN\n        ALTER TABLE public.profiles ADD COLUMN age INTEGER;\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='gender') THEN\n        ALTER TABLE public.profiles ADD COLUMN gender TEXT;\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='credits') THEN\n        ALTER TABLE public.profiles ADD COLUMN credits INTEGER DEFAULT 0;\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='doctor_code') THEN\n        ALTER TABLE public.profiles ADD COLUMN doctor_code TEXT UNIQUE;\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='assigned_doctor_id') THEN\n        ALTER TABLE public.profiles ADD COLUMN assigned_doctor_id UUID REFERENCES public.profiles(id);\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='license_number') THEN\n        ALTER TABLE public.profiles ADD COLUMN license_number TEXT;\n    END IF;\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='profiles' AND column_name='is_approved') THEN\n        ALTER TABLE public.profiles ADD COLUMN is_approved BOOLEAN DEFAULT FALSE;\n    END IF;\nEND ;\n\n-- 2. 진단 기록 누적 테이블 (History)\nCREATE TABLE IF NOT EXISTS public.diagnostic_results (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id UUID REFERENCES public.profiles(id) NOT NULL,\n  test_type TEXT DEFAULT 'CSEI-28',\n  raw_scores JSONB NOT NULL,\n  t_scores JSONB NOT NULL,\n  risk_level TEXT,\n  is_premium_revealed BOOLEAN DEFAULT FALSE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL\n);\n\n-- 3. 의료진-환자 배정 추적 테이블\nCREATE TABLE IF NOT EXISTS public.medical_assignments (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  doctor_id UUID REFERENCES public.profiles(id) NOT NULL,\n  patient_id UUID REFERENCES public.profiles(id) NOT NULL,\n  assigned_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,\n  UNIQUE(doctor_id, patient_id)\n);\n\n-- 4. 로우 레벨 보안 (RLS) 설정\nALTER TABLE public.diagnostic_results ENABLE ROW LEVEL SECURITY;\n\nDROP POLICY IF EXISTS " Doctors can view assigned patients results\ ON public.diagnostic_results;\nCREATE POLICY \Doctors can view assigned patients results\\nON public.diagnostic_results FOR SELECT\nUSING (\n EXISTS (\n SELECT 1 FROM public.medical_assignments\n WHERE doctor_id = auth.uid() AND patient_id = diagnostic_results.user_id\n )\n);\n\nDROP POLICY IF EXISTS \Users can view own results\ ON public.diagnostic_results;\nCREATE POLICY \Users can view own results\\nON public.diagnostic_results FOR SELECT\nUSING (auth.uid() = user_id);\n